#!/usr/bin/env python3
"""
encode-hybrid.py — Spectral + residual ("LoRA-inverse") GKQ encoder.

Companion to encode-real-model.py. For each spectral target tensor W
(attn Q/K/V/O, FFN gate/up/down) this encoder writes:

  1. A spectral block       :: name        = "blk.N.attn_q.weight"           (existing GKQ v2 layout)
       U·diag(σ)·Vᵀ at rank K (the concept-axis sketch)
  2. A dense residual block :: name        = "blk.N.attn_q.weight__residual" (NEW)
       R = W - U_K·diag(σ_K)·V_K^T  ∈ {F32, F16, Q4_K} per --residual-dtype

The fat-station GkqBackend (src/gkq_backend.rs) was extended to look for the
"__residual" twin after reconstructing the spectral half and elementwise-add
it to the spectral W. This re-shapes the on-disk format from "lossy spectral
sketch" to "(spectral sketch) + (~half-size Q4_K residual) = argmax-stable
reconstruction".

Stages (per --residual-dtype):
  Stage 1 (f32) : exact reconstruction modulo float roundoff — wiring sanity check.
  Stage 2 (f16) : ~0.5% per-element error — fast iteration.
  Stage 3 (q4_k): ~5% per-element error  — real compression test.

Usage:
    python3 encode-hybrid.py --model Qwen/Qwen2.5-0.5B-Instruct \
        --output /tmp/qwen-0.5b-hybrid-f32.knot \
        --rank 64 \
        --residual-dtype f32
"""

from __future__ import annotations

import argparse
import os
import re
import struct
import sys
import time
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import numpy as np

_HERE = Path(__file__).resolve().parent
sys.path.insert(0, str(_HERE))
import gkq_v2_format as gkq  # noqa: E402

# encode-real-model.py uses a hyphenated name; import via importlib machinery
# to reuse `_spectral_quantize`, `_to_numpy`, etc.
import importlib.util as _il_util

_ERM_PATH = _HERE / "encode-real-model.py"
_spec = _il_util.spec_from_file_location("encode_real_model_mod", str(_ERM_PATH))
_erm = _il_util.module_from_spec(_spec)
_spec.loader.exec_module(_erm)


# ─────────────────────────────────────────────────────────────────────────────
# Q4_K QUANTIZER (256-element block, 144-byte payload)
# ─────────────────────────────────────────────────────────────────────────────
# Layout (matches llama.cpp / fat-station dequantize_q4k_row, src/math.rs:71):
#   bytes  0..2  : d    (f16) — main scale
#   bytes  2..4  : dmin (f16) — main min
#   bytes  4..16 : scales (12 bytes — eight 6-bit sub-scales + eight 6-bit sub-mins)
#   bytes 16..144: qs (128 bytes = 256 nibbles, 8 sub-blocks of 32 elements)
#
# Each block dequantizes as: out[i] = d * sc_sub - dmin * m_sub, where sc_sub,
# m_sub are the per-sub-block scale/min and q is the 4-bit nibble.
#
# 6-bit packing follows ggml's get_scale_min_k4: sub-blocks 0..4 store low 6
# bits in scales[0..4] (sc) and scales[4..8] (m). Sub-blocks 4..8 store the
# low 4 bits in scales[8..12] (high nibble = m, low nibble = sc) plus the
# top 2 bits in the high pair of scales[0..4] (sc) and scales[4..8] (m).


def _f32_to_f16(x: float) -> int:
    """Encode a Python float as a u16 IEEE-754 half-precision value."""
    return int(np.float16(x).view(np.uint16))


def _pack_scales_mins(sc: np.ndarray, m: np.ndarray) -> bytes:
    """Pack eight 6-bit sub-scales `sc` and eight 6-bit sub-mins `m` into 12 bytes.

    Inverse of get_scale_min_k4. `sc` and `m` are uint8 arrays of length 8 with
    values in 0..63.
    """
    assert sc.shape == (8,) and m.shape == (8,)
    sc = np.clip(sc.astype(np.uint8), 0, 63)
    m = np.clip(m.astype(np.uint8), 0, 63)
    out = bytearray(12)
    # Sub-blocks 0..4: low 6 bits in scales[0..4] / scales[4..8]
    for j in range(4):
        out[j] = (sc[j] & 0x3F) | (((sc[j + 4] >> 4) & 0x03) << 6)
        out[j + 4] = (m[j] & 0x3F) | (((m[j + 4] >> 4) & 0x03) << 6)
    # Sub-blocks 4..8: low 4 bits in scales[8..12]
    for j in range(4):
        out[j + 8] = (sc[j + 4] & 0x0F) | ((m[j + 4] & 0x0F) << 4)
    return bytes(out)


def _quantize_q4k_block(weights_256: np.ndarray) -> bytes:
    """Quantize 256 f32 weights into one 144-byte Q4_K super-block.

    Approach: split into 8 sub-blocks of 32 elements. For each sub-block, find
    (sub_min, sub_max). Solve per-block scale (d) and min (dmin) by treating
    the per-sub-block (sub_scale = (sub_max - sub_min)/15) and
    (sub_offset = -sub_min/sub_scale) as quantized 6-bit fixed-point — d
    normalizes the sub_scales to fit in 6 bits, dmin normalizes the sub_mins
    to fit in 6 bits.

    Symmetric / mean-preserving: out[i] = d * sc * q - dmin * m, where
    q ∈ {0..15}, sc ∈ {0..63}, m ∈ {0..63}, d, dmin ∈ f16.
    """
    assert weights_256.shape == (256,), f"got {weights_256.shape}"
    w = weights_256.astype(np.float32)

    sub = w.reshape(8, 32)
    sub_min = sub.min(axis=1)              # [8]
    sub_max = sub.max(axis=1)              # [8]
    sub_range = sub_max - sub_min          # [8]
    # raw sub-scale s.t. q ≈ (x - sub_min)/sub_scale,
    #   where q is in 0..15
    # sub_scale * 15 = sub_range  →  sub_scale = sub_range / 15
    # We'll express sub_scale = d * sc_q and sub_min(negated)
    # via dmin * m_q where sc_q, m_q ∈ {0..63}
    sub_scale = sub_range / 15.0
    # Use the negative-min convention to match dequantize formula
    # out = d*sc*q - dmin*m   so   x ≈ d*sc*q + (-dmin*m)
    # i.e.  -dmin*m  models the sub_min:   -dmin*m = sub_min   ⇒  dmin*m = -sub_min
    sub_neg_min = -sub_min                 # may be negative if sub_min > 0
    # Clamp negatives to 0 — dequant cannot subtract a negative; in that case
    # we let the min be 0 and pay the cost in scale precision. This is the
    # llama.cpp convention.
    sub_neg_min = np.clip(sub_neg_min, 0.0, None)

    # Pick d so the largest sub_scale fits in 6 bits (max 63).
    max_sub_scale = sub_scale.max()
    max_sub_min = sub_neg_min.max()
    inv_d = 63.0 / max(max_sub_scale, 1e-30)
    inv_dmin = 63.0 / max(max_sub_min, 1e-30)
    d = max_sub_scale / 63.0
    dmin = max_sub_min / 63.0

    sc_q = np.clip(np.round(sub_scale * inv_d), 0, 63).astype(np.uint8)
    m_q = np.clip(np.round(sub_neg_min * inv_dmin), 0, 63).astype(np.uint8)

    # Now quantize each sub-block to nibbles using the chosen sub_scale / sub_min.
    # Recover the actual effective sub_scale, sub_min the decoder will use:
    eff_sub_scale = d * sc_q.astype(np.float32)         # [8]
    eff_sub_neg_min = dmin * m_q.astype(np.float32)     # [8]

    nibbles = np.zeros((8, 32), dtype=np.uint8)
    for s in range(8):
        es = eff_sub_scale[s]
        if es <= 1e-30:
            # All zeros in this sub-block (or precision lost) — quantize to 0.
            nibbles[s] = 0
            continue
        # Inverse: q ≈ (x + eff_sub_neg_min) / es
        q = np.round((sub[s] + eff_sub_neg_min[s]) / es)
        nibbles[s] = np.clip(q, 0, 15).astype(np.uint8)

    # Pack nibbles into qs[128] (low 4 bits = first 32 elems of even sub-block,
    # high 4 bits = first 32 elems of odd sub-block — i.e. sub-blocks 0|1 fuse
    # into qs[0..32], sub-blocks 2|3 fuse into qs[32..64], etc.)
    qs = np.zeros(128, dtype=np.uint8)
    for pair in range(4):
        s_lo = 2 * pair
        s_hi = 2 * pair + 1
        base = pair * 32
        qs[base:base + 32] = (nibbles[s_lo] & 0x0F) | ((nibbles[s_hi] & 0x0F) << 4)

    out = bytearray(144)
    out[0:2] = struct.pack("<H", _f32_to_f16(d))
    out[2:4] = struct.pack("<H", _f32_to_f16(dmin))
    out[4:16] = _pack_scales_mins(sc_q, m_q)
    out[16:144] = qs.tobytes()
    return bytes(out)


def quantize_q4k(arr: np.ndarray) -> bytes:
    """Quantize a 2-D weight matrix to Q4_K.

    arr must be shape (d_out, d_in) with d_in divisible by 256. Returns raw
    bytes laid out row-by-row, each row consisting of (d_in/256) 144-byte blocks.
    """
    if arr.ndim != 2:
        raise ValueError(f"quantize_q4k expects 2-D, got shape {arr.shape}")
    d_out, d_in = arr.shape
    if d_in % 256 != 0:
        raise ValueError(
            f"quantize_q4k: d_in ({d_in}) must be divisible by 256 for Q4_K block layout"
        )
    blocks_per_row = d_in // 256
    out = bytearray(d_out * blocks_per_row * 144)
    cursor = 0
    arr_f32 = arr.astype(np.float32, copy=False)
    for r in range(d_out):
        row = arr_f32[r]
        for b in range(blocks_per_row):
            blk = row[b * 256:(b + 1) * 256]
            out[cursor:cursor + 144] = _quantize_q4k_block(blk)
            cursor += 144
    return bytes(out)


def dequantize_q4k_row_for_test(row_bytes: bytes, d_in: int) -> np.ndarray:
    """Pure-Python mirror of dequantize_q4k_row (math.rs:71). For roundtrip tests."""
    bpr = d_in // 256
    out = np.zeros(d_in, dtype=np.float32)
    for b in range(bpr):
        bp = row_bytes[b * 144:(b + 1) * 144]
        d_val = float(np.frombuffer(bp[0:2], dtype=np.float16)[0])
        dmin = float(np.frombuffer(bp[2:4], dtype=np.float16)[0])
        scales = bp[4:16]
        qs = bp[16:144]
        o = b * 256
        for j in range(0, 256, 64):
            sc1, m1 = _get_scale_min_k4(j // 32, scales)
            sc2, m2 = _get_scale_min_k4(j // 32 + 1, scales)
            qb = (j // 64) * 32
            for l in range(32):
                q_lo = qs[qb + l] & 0xF
                q_hi = qs[qb + l] >> 4
                out[o + j + l] = d_val * sc1 * q_lo - dmin * m1
                out[o + j + 32 + l] = d_val * sc2 * q_hi - dmin * m2
    return out


def _get_scale_min_k4(j: int, scales: bytes) -> tuple:
    if j < 4:
        return (float(scales[j] & 63), float(scales[j + 4] & 63))
    else:
        sc = (scales[j + 4] & 0xF) | ((scales[j - 4] >> 6) << 4)
        m = (scales[j + 4] >> 4) | ((scales[j] >> 6) << 4)
        return (float(sc), float(m))


# ─────────────────────────────────────────────────────────────────────────────
# Residual quantization dispatchers
# ─────────────────────────────────────────────────────────────────────────────


def _residual_to_dense_payload(
    residual: np.ndarray, dtype: str
) -> Tuple[bytes, int, Tuple[int, ...]]:
    """Quantize a residual matrix for storage as a dense GKQ tensor.

    Returns (raw_bytes, dtype_code, dims).
    """
    if dtype == "f32":
        arr = residual.astype(np.float32, copy=False)
        return arr.tobytes(), gkq.DTYPE_F32, arr.shape
    if dtype == "f16":
        arr = residual.astype(np.float16, copy=False)
        return arr.tobytes(), gkq.DTYPE_F16, arr.shape
    if dtype == "q4_k":
        d_out, d_in = residual.shape
        if d_in % 256 != 0:
            # Fall back to f16 for non-Q4_K-shaped tensors (rare; gate_proj etc.
            # are all divisible by 256 on Qwen2.5). Print a warning so we know.
            print(
                f"[hybrid] WARNING: d_in={d_in} not divisible by 256; "
                "falling back to F16 residual for this tensor",
                file=sys.stderr,
            )
            arr = residual.astype(np.float16, copy=False)
            return arr.tobytes(), gkq.DTYPE_F16, arr.shape
        raw = quantize_q4k(residual)
        return raw, gkq.DTYPE_Q4_K, (d_out, d_in)
    raise ValueError(f"unknown --residual-dtype: {dtype}")


# ─────────────────────────────────────────────────────────────────────────────
# Hybrid encoder — spectral + residual twin per spectral tensor
# ─────────────────────────────────────────────────────────────────────────────


def encode_hybrid(
    items: List[Tuple[str, object]],
    *,
    model_name: str,
    arch: str,
    knot_config: dict,
    output_path: str,
    max_layers: Optional[int],
    to_numpy=lambda x: x,
    tie_word_embeddings: bool = False,
    rank: int = gkq.RANK_DEFAULT,
    residual_dtype: str = "f32",
) -> dict:
    """Walk `items` and write a hybrid GKQ file.

    For every spectral tensor we emit BOTH a spectral block AND a dense residual
    block named `<canonical>__residual`. Norms / embeddings / lm_head go through
    the dense path unchanged (they're small or critical; no SVD).
    """
    # Pass 1: classify and detect tied embeddings (same logic as encode-real-model).
    classified: List[Tuple[str, str, object]] = []
    seen: Dict[str, Tuple[str, str]] = {}
    aliases: List[Tuple[str, str]] = []
    name_to_ptr: Dict[str, int] = {}

    def _data_ptr(t) -> Optional[int]:
        try:
            return int(t.data_ptr())
        except Exception:
            return None

    for hf_name, tensor in items:
        mapped = _erm.map_tensor_name(hf_name, max_layers)
        if mapped is None:
            continue
        canonical, kind = mapped
        if canonical in seen:
            continue
        seen[canonical] = (hf_name, kind)
        ptr = _data_ptr(tensor)
        if ptr is not None:
            name_to_ptr[canonical] = ptr
        classified.append((canonical, kind, tensor))

    # Tied embeddings (storage-shared OR config flag) → alias output.weight.
    embed_ptr = name_to_ptr.get("token_embd.weight")
    out_ptr = name_to_ptr.get("output.weight")
    if embed_ptr is not None and out_ptr is not None and embed_ptr == out_ptr:
        classified = [(c, k, t) for c, k, t in classified if c != "output.weight"]
        aliases.append(("output.weight", "token_embd.weight"))
        print("[hybrid] tied weights (shared data_ptr): aliasing output.weight → token_embd.weight")
    elif tie_word_embeddings and "output.weight" not in seen and "token_embd.weight" in seen:
        aliases.append(("output.weight", "token_embd.weight"))
        print("[hybrid] tied weights (config flag): aliasing output.weight → token_embd.weight")
    elif tie_word_embeddings and "output.weight" in seen and "token_embd.weight" in seen:
        classified = [(c, k, t) for c, k, t in classified if c != "output.weight"]
        aliases.append(("output.weight", "token_embd.weight"))
        print("[hybrid] tied weights (config flag, both present): aliasing output.weight → token_embd.weight")

    # Hybrid: each spectral target generates BOTH a spectral block AND a
    # residual dense block. The residual is named `<canonical>__residual`.
    spectral_items = sorted([(c, t) for c, k, t in classified if k == "spectral"], key=lambda x: x[0])
    dense_items = sorted([(c, t) for c, k, t in classified if k == "dense"], key=lambda x: x[0])

    num_spectral = len(spectral_items)
    num_dense = len(dense_items) + len(spectral_items) + len(aliases)  # +1 residual per spectral

    print(f"[hybrid] classified {len(classified)} tensors: "
          f"{num_spectral} spectral + {num_spectral} residual + "
          f"{len(dense_items)} dense + {len(aliases)} alias")
    print(f"[hybrid] spectral rank: {rank}; residual dtype: {residual_dtype}")

    out_path = Path(output_path)
    out_path.parent.mkdir(parents=True, exist_ok=True)

    spectral_bytes = 0
    residual_bytes = 0
    dense_bytes = 0
    worst_spec_err = 0.0
    worst_spec_err_name = ""
    worst_resid_err = 0.0
    worst_resid_err_name = ""
    t_start = time.time()

    with open(out_path, "wb") as f:
        gkq.write_header(f, model_name, arch, knot_config, num_spectral, num_dense)

        # ── Spectral blocks (per existing GKQ v2 spec) ──
        # We materialize the residual immediately and stash it for the dense
        # pass below.
        residuals: List[Tuple[str, np.ndarray]] = []
        for idx, (canonical, tensor) in enumerate(spectral_items):
            arr = to_numpy(tensor)
            arr = np.ascontiguousarray(arr, dtype=np.float32)
            if arr.ndim != 2:
                arr = arr.reshape(arr.shape[0], -1)
            (u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max,
             d_out, d_in, rel_err, eff_rank) = _erm._spectral_quantize(arr, rank=rank)
            if rel_err > worst_spec_err:
                worst_spec_err = rel_err
                worst_spec_err_name = canonical

            # Reconstruct spectral W_K to compute residual.
            # Decoder side does:
            #   U_dq    = ((u_q8 - 128) / 127) * u_max
            #   sigma_dq= (sigma_q8 / 255) * sigma_max
            #   Vt_dq   = ((v_q8 - 128) / 127) * v_max
            #   W_K     = (U_dq * sigma_dq) @ Vt_dq
            # We match the decoder exactly so the residual lands at the same
            # numerical reference frame.
            U_dq = ((u_q8.astype(np.float32) - 128.0) / 127.0) * u_max
            sigma_dq = (sigma_q8.astype(np.float32) / 255.0) * sigma_max
            Vt_dq = ((v_q8.astype(np.float32) - 128.0) / 127.0) * v_max
            W_K = (U_dq * sigma_dq[np.newaxis, :]) @ Vt_dq
            residual = arr.astype(np.float32) - W_K.astype(np.float32)

            before = f.tell()
            gkq.write_spectral_tensor(
                f, canonical, u_q8, sigma_q8, v_q8,
                u_max, sigma_max, v_max, d_out, d_in, rank=eff_rank,
            )
            spectral_bytes += f.tell() - before
            residuals.append((canonical, residual))
            if (idx + 1) % 24 == 0 or idx + 1 == num_spectral:
                print(f"[hybrid] spectral {idx + 1}/{num_spectral}: {canonical} "
                      f"({d_out}×{d_in}) rel_err={rel_err:.4f}")

        # ── Dense non-alias blocks: original dense + per-spectral residual ──
        # Original dense first (norms, embed, biases, lm_head), then residuals.
        for canonical, tensor in dense_items:
            arr = to_numpy(tensor)
            if arr.dtype == np.float16 or arr.dtype == np.float32:
                pass
            else:
                arr = arr.astype(np.float32)
            arr = np.ascontiguousarray(arr)
            before = f.tell()
            gkq.write_dense_tensor(f, canonical, arr)
            dense_bytes += f.tell() - before

        # Residuals.
        for canonical, residual in residuals:
            raw, dtype_code, dims = _residual_to_dense_payload(residual, residual_dtype)
            # Compute roundtrip error for the worst-resid stat. We only
            # roundtrip for f16/q4_k since f32 is exact.
            if residual_dtype == "f32":
                rt_err = 0.0
            elif residual_dtype == "f16":
                rt = np.frombuffer(raw, dtype=np.float16).astype(np.float32).reshape(dims)
                denom = float(np.linalg.norm(residual, "fro")) + 1e-12
                rt_err = float(np.linalg.norm(residual - rt, "fro") / denom)
            else:  # q4_k — roundtrip per-row via the pure-Python dequant (slow; spot-check)
                # Only roundtrip-check the first row to bound elapsed time on big tensors.
                d_out, d_in = dims
                if d_in % 256 == 0:
                    row_bytes_count = (d_in // 256) * 144
                    row0_dq = dequantize_q4k_row_for_test(raw[:row_bytes_count], d_in)
                    denom = float(np.linalg.norm(residual[0]) + 1e-12)
                    rt_err = float(np.linalg.norm(residual[0] - row0_dq) / denom)
                else:
                    # Fell back to F16 (see _residual_to_dense_payload)
                    rt = np.frombuffer(raw, dtype=np.float16).astype(np.float32).reshape(dims)
                    denom = float(np.linalg.norm(residual, "fro")) + 1e-12
                    rt_err = float(np.linalg.norm(residual - rt, "fro") / denom)
            if rt_err > worst_resid_err:
                worst_resid_err = rt_err
                worst_resid_err_name = canonical

            # Use a synthetic ndarray for write_dense_tensor's shape inference.
            shape_arr = np.empty(dims, dtype=np.uint8)  # only .shape is read
            before = f.tell()
            gkq.write_dense_tensor(
                f, canonical + "__residual", shape_arr,
                dtype_code=dtype_code, raw_bytes=raw,
            )
            residual_bytes += f.tell() - before

        # Aliases.
        for alias_name, alias_target in sorted(aliases):
            before = f.tell()
            gkq.write_dense_alias(f, alias_name, alias_target)
            dense_bytes += f.tell() - before

    elapsed = time.time() - t_start
    file_size = out_path.stat().st_size
    summary = {
        "output_path": str(out_path),
        "file_size_bytes": file_size,
        "file_size_mb": file_size / 1e6,
        "num_spectral": num_spectral,
        "num_residual": num_spectral,
        "num_dense": num_dense,
        "spectral_bytes": spectral_bytes,
        "residual_bytes": residual_bytes,
        "dense_bytes": dense_bytes,
        "worst_spectral_rel_err": worst_spec_err,
        "worst_spectral_rel_err_name": worst_spec_err_name,
        "worst_residual_rt_err": worst_resid_err,
        "worst_residual_rt_err_name": worst_resid_err_name,
        "elapsed_sec": elapsed,
        "residual_dtype": residual_dtype,
        "rank": rank,
    }
    return summary


def _print_summary(s: dict) -> None:
    print("─" * 64)
    print(f"GKQ hybrid file written: {s['output_path']}")
    print(f"  size:                  {s['file_size_mb']:.2f} MB ({s['file_size_bytes']:,} bytes)")
    print(f"  spectral tensors:      {s['num_spectral']} ({s['spectral_bytes']:,} bytes)")
    print(f"  residual tensors:      {s['num_residual']} ({s['residual_bytes']:,} bytes, dtype={s['residual_dtype']})")
    print(f"  other dense tensors:   {s['num_dense'] - s['num_residual']} ({s['dense_bytes']:,} bytes)")
    print(f"  worst SVD rel-err:     {s['worst_spectral_rel_err']:.4f}  ({s['worst_spectral_rel_err_name']})")
    print(f"  worst residual roundtrip err: {s['worst_residual_rt_err']:.4f}  ({s['worst_residual_rt_err_name']})")
    print(f"  elapsed:               {s['elapsed_sec']:.1f}s")
    print("─" * 64)


# ─────────────────────────────────────────────────────────────────────────────
# CLI (HF-mode only; synthetic mode lives in encode-real-model.py for sanity)
# ─────────────────────────────────────────────────────────────────────────────


def parse_args(argv=None):
    p = argparse.ArgumentParser(description="Encode a real HF causal-LM into GKQ hybrid (spectral + residual).")
    p.add_argument("--model", required=True, help="HF model id or local path (e.g. Qwen/Qwen2.5-0.5B-Instruct)")
    p.add_argument("--output", required=True, help="Output .knot path")
    p.add_argument("--model-name", default=None, help="Override model name stored in the header")
    p.add_argument("--max-layers", type=int, default=None, help="Encode only first N transformer layers")
    p.add_argument("--rank", type=int, default=gkq.RANK_DEFAULT,
                   help=f"Spectral rank per weight matrix (default: {gkq.RANK_DEFAULT})")
    p.add_argument("--residual-dtype", choices=["f32", "f16", "q4_k"], default="q4_k",
                   help="Residual storage dtype (default: q4_k)")
    return p.parse_args(argv)


def main(argv=None) -> int:
    args = parse_args(argv)

    try:
        import torch
        from transformers import AutoConfig, AutoModelForCausalLM
    except Exception as e:  # pragma: no cover
        print(f"ERROR: transformers/torch not available: {e}", file=sys.stderr)
        return 2

    print(f"[hybrid] loading model {args.model} on CPU…")
    model = AutoModelForCausalLM.from_pretrained(
        args.model, torch_dtype=torch.float32, device_map="cpu", low_cpu_mem_usage=True
    )
    hf_config = model.config
    arch = _erm.detect_arch(hf_config)
    knot_config = _erm.build_knot_config(hf_config, arch, args.max_layers)
    tie = bool(getattr(hf_config, "tie_word_embeddings", False))

    state = list(model.state_dict().items())
    print(f"[hybrid] state_dict has {len(state)} tensors; arch={arch}")

    summary = encode_hybrid(
        items=state,
        model_name=args.model_name or args.model,
        arch=arch,
        knot_config=knot_config,
        output_path=args.output,
        max_layers=args.max_layers,
        to_numpy=_erm._to_numpy,
        tie_word_embeddings=tie,
        rank=args.rank,
        residual_dtype=args.residual_dtype,
    )
    _print_summary(summary)
    return 0


# ─────────────────────────────────────────────────────────────────────────────
# Standalone smoke test (no HF). Run with `python3 encode-hybrid.py --selftest`.
# ─────────────────────────────────────────────────────────────────────────────


def _selftest():
    """Q4_K quantize → dequantize roundtrip on a small matrix."""
    rng = np.random.default_rng(0)
    arr = rng.standard_normal((4, 512)).astype(np.float32) * 0.05
    raw = quantize_q4k(arr)
    expected_bytes = 4 * (512 // 256) * 144
    assert len(raw) == expected_bytes, f"got {len(raw)} expected {expected_bytes}"

    # Dequantize via pure-python mirror.
    row_bytes_count = (512 // 256) * 144
    reconstructed = np.zeros_like(arr)
    for r in range(4):
        reconstructed[r] = dequantize_q4k_row_for_test(
            raw[r * row_bytes_count:(r + 1) * row_bytes_count], 512
        )
    err = float(np.linalg.norm(arr - reconstructed) / (np.linalg.norm(arr) + 1e-12))
    print(f"[selftest] Q4_K roundtrip rel-err on N(0, 0.05) 4×512: {err:.4f}")
    assert err < 0.10, f"Q4_K roundtrip err too high: {err}"
    print("[selftest] OK")


if __name__ == "__main__":
    if "--selftest" in sys.argv:
        _selftest()
        sys.exit(0)
    raise SystemExit(main())
